 {"id":"bd-3bxhj.4.3","title":"task(opentui-import translation): Translate state and event semantics into ftui-runtime Model/update/subscriptions","description":"Objective: Generate idiomatic ftui-runtime model code from IR state/event/effect graphs while preserving deterministic behavior and cancellation semantics.\n\nAcceptance criteria:\n1. Generated update logic preserves source transition invariants.\n2. Subscriptions and command boundaries reflect canonical effect model.\n3. Generated code obeys one-writer and deterministic runtime constraints.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:32:04.115898482Z","created_by":"ubuntu","updated_at":"2026-02-24T21:37:29.565113565Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["opentui-import","runtime","translation"],"dependencies":[{"issue_id":"bd-3bxhj.4.3","depends_on_id":"bd-3bxhj.3.5","type":"blocks","created_at":"2026-02-24T21:37:29.565043654Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.4.3","depends_on_id":"bd-3bxhj.4","type":"parent-child","created_at":"2026-02-24T21:32:04.115898482Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.4.3","depends_on_id":"bd-3bxhj.4.2","type":"blocks","created_at":"2026-02-24T21:37:29.112630954Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.4.4","title":"task(opentui-import translation): Translate view/layout semantics into ftui-layout and widget composition","description":"Objective: Generate view code that maps IR layout and composition semantics into ftui-layout and ftui-widgets primitives with deterministic tree ordering.\n\nAcceptance criteria:\n1. Generated widget hierarchy preserves interaction/focus semantics.\n2. Layout translation honors constraints and fallback rules from policy matrix.\n3. Emitted view code remains readable and modular for human maintenance.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:32:08.537382661Z","created_by":"ubuntu","updated_at":"2026-02-24T21:37:30.510390555Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["layout-widgets","opentui-import","translation"],"dependencies":[{"issue_id":"bd-3bxhj.4.4","depends_on_id":"bd-3bxhj.3.4","type":"blocks","created_at":"2026-02-24T21:37:30.510326756Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.4.4","depends_on_id":"bd-3bxhj.4","type":"parent-child","created_at":"2026-02-24T21:32:08.537382661Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.4.4","depends_on_id":"bd-3bxhj.4.2","type":"blocks","created_at":"2026-02-24T21:37:30.026588552Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.4.5","title":"task(opentui-import translation): Translate style/theme semantics into ftui-style with accessibility-safe upgrades","description":"Objective: Convert style intent and token systems into ftui-style while applying safe improvements (contrast fixes, redundant style simplification) within approved envelope.\n\nAcceptance criteria:\n1. Style translation preserves intended hierarchy and overrides.\n2. Accessibility-safe upgrades are annotated and reversible.\n3. Generated theme artifacts include provenance from source tokens.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:32:13.105712549Z","created_by":"ubuntu","updated_at":"2026-02-24T21:37:31.447223327Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["opentui-import","style","translation"],"dependencies":[{"issue_id":"bd-3bxhj.4.5","depends_on_id":"bd-3bxhj.2.7","type":"blocks","created_at":"2026-02-24T21:37:31.447153366Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.4.5","depends_on_id":"bd-3bxhj.4","type":"parent-child","created_at":"2026-02-24T21:32:13.105712549Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.4.5","depends_on_id":"bd-3bxhj.4.2","type":"blocks","created_at":"2026-02-24T21:37:30.975858793Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
